compliant:
if (x > 0) {
    DoSomething();
} else if (x < 0) {
    DoSomethingElse();
} else {
    DoDefault();
}

if (status == Status.Active) {
    Process();
} else if (status == Status.Inactive) {
    Skip();
} else if (status == Status.Pending) {
    Queue();
}
